openscad:
$fn = 60;
dial_diameter = 40; // [20:1:80]
case_height = 6; // [3:0.5:12]
bezel_width = 4; // [1:0.5:8]
hand_thickness = 1.2; // [0.5:0.1:3]
hour_hand_length = 12; // [5:1:25]
minute_hand_length = 16; // [8:1:30]
second_hand_length = 17; // [8:1:30]
strap_width = 20; // [10:1:30]
strap_length = 50; // [20:5:80]
color_case = "gray";
color_dial = "white";
color_bezel = "yellow";
color_hands = "black";
union() {
  color(color_case)
  difference() {
    cylinder(h=case_height, d=dial_diameter+bezel_width*2, center=true);
    translate([0,0,case_height/2-1])
      cylinder(h=case_height, d=dial_diameter+1, center=true);
  }
  color(color_dial)
  cylinder(h=case_height-1, d=dial_diameter, center=true);
  color(color_bezel)
  difference() {
    cylinder(h=case_height-0.5, d=dial_diameter+bezel_width, center=true);
    cylinder(h=case_height, d=dial_diameter-2, center=true);
  }
  for (i=[0:11]) {
    rotate([0,0,i*30])
      translate([dial_diameter/2-3,0,case_height/2-0.2])
        color("black")
        cube([4,1.5,0.6], center=true);
  }
  color(color_hands)
  translate([0,0,case_height/2+0.5]) {
    rotate([0,0,30])
      linear_extrude(height=1.5)
        polygon(points=[[0,-hand_thickness/2],[hour_hand_length,-hand_thickness/4],[hour_hand_length,hand_thickness/4],[0,hand_thickness/2]]);
    rotate([0,0,120])
      linear_extrude(height=1.5)
        polygon(points=[[0,-hand_thickness/2],[minute_hand_length,-hand_thickness/4],[minute_hand_length,hand_thickness/4],[0,hand_thickness/2]]);
    rotate([0,0,200])
      cylinder(h=2, d=0.8, center=false);
  }
  color(color_case) {
    translate([-dial_diameter/2-bezel_width-strap_length, -strap_width/2, -case_height/2])
      cube([strap_length, strap_width, 3]);
    translate([dial_diameter/2+bezel_width, -strap_width/2, -case_height/2])
      cube([strap_length, strap_width, 3]);
  }
}
